{
  "terms": [
    {
      "term": "Atom",
      "simpleDefinition": "The smallest unit of matter that makes up everything, consisting of a central nucleus and orbiting electrons.",
      "anchor": "The basic building block of every material in an electrical circuit.",
      "misconception": "Thinking an atom is a solid object rather than mostly empty space with moving parts."
    },
    {
      "term": "Nucleus",
      "simpleDefinition": "The heavy center of an atom containing protons and neutrons; it stays stationary during electrical flow.",
      "anchor": "The 'anchor' of the atom that holds the positive charge.",
      "misconception": "Believing the nucleus moves through the wire when electricity flows."
    },
    {
      "term": "Proton",
      "simpleDefinition": "A subatomic particle with a positive charge located in the nucleus.",
      "anchor": "P for Positive.",
      "misconception": "Thinking protons are the particles that move to create an electric current."
    },
    {
      "term": "Electron",
      "simpleDefinition": "A tiny, negatively charged particle that orbits the nucleus of an atom.",
      "anchor": "The 'fuel' of electricity; their movement is what we call current.",
      "misconception": "Thinking electrons are only present when the power is turned on."
    },
    {
      "term": "Neutron",
      "simpleDefinition": "A subatomic particle in the nucleus with no electrical charge.",
      "anchor": "N for Neutral.",
      "misconception": "Thinking neutrons play an active role in conducting electricity."
    },
    {
      "term": "Valence Shell",
      "simpleDefinition": "The outermost orbit or 'ring' of an atom where electrons can be gained or lost.",
      "anchor": "The 'exit door' for electrons to leave the atom.",
      "misconception": "Thinking all electrons in an atom are equally likely to break away."
    },
    {
      "term": "Free Electron",
      "simpleDefinition": "An electron that has broken away from its parent atom and is able to move through a material.",
      "anchor": "The actual 'drifters' that form an electric current.",
      "misconception": "Believing that every electron in a piece of copper is 'free' at the same time."
    },
    {
      "term": "Conductor",
      "simpleDefinition": "A material (usually metal) that has many free electrons, allowing electricity to flow easily.",
      "anchor": "Copper or aluminum wiring.",
      "misconception": "Thinking a conductor 'creates' electricity rather than just providing a path for it."
    },
    {
      "term": "Insulator",
      "simpleDefinition": "A material where electrons are tightly bound to their atoms, preventing the flow of electricity.",
      "anchor": "The PVC plastic coating on a cable.",
      "misconception": "Believing insulators have no electrons; they have them, but they are 'locked' in place."
    }
  ],
  "anchorPhrases": [
    "Opposites attract, likes repel.",
    "Electricity is the movement of free electrons.",
    "Conductors let them go; insulators hold them tight.",
    "The valence shell determines the material's job."
  ],
  "misconceptionTargets": [
    "The idea that the nucleus or protons move during current flow.",
    "The belief that insulators are 'empty' of electrons.",
    "Confusing the terms 'atom' and 'electron' as being the same thing."
  ]
}

