{
  "guidedPractice": {
    "title": "Guided Practice: Material Analysis",
    "objective": "Explain the difference between a conductor and an insulator using the concept of the valence shell.",
    "retrievalTextLines": [
      "Scenario: You are looking at an overhead power line made of Aluminum strands covered by a thick layer of Polyethylene insulation.",
      "Step 1: Identify the conductor. Aluminum is a metal. Look at its valence shell (the outermost orbit).",
      "Step 2: Identify the insulator. Polyethylene is a plastic. Look at how its electrons are held.",
      "Step 3: Compare the 'grip' of the nucleus in both materials."
    ],
    "questionText": "Using the example of the Aluminum wire and Polyethylene insulation, explain why one allows electricity to flow while the other prevents it, specifically referencing the state of the electrons in their valence shells.",
    "answerGuidance": [
      "Aluminum is a conductor because its valence electrons are loosely held and can become free electrons, while Polyethylene is an insulator because its electrons are tightly bound to the nucleus and cannot move easily."
    ],
    "hint": "Think about which material has 'free electrons' and which one keeps them 'locked' in place."
  },
  "practice": {
    "title": "Independent Practice: Gold vs. Rubber",
    "objective": "Apply electron theory to justify the use of specific materials in electrical components.",
    "retrievalTextLines": [
      "In high-end data cables, Gold is often used for the contact pins, while Rubber or Silicone is used for the outer grip.",
      "Recall the definition of a 'free electron' and how the atomic structure of a material determines its ability to conduct or insulate."
    ],
    "questionText": "Explain, in terms of atomic structure and electron theory, why Gold is used for the internal pins of a connector while Rubber is used for the external handle.",
    "answerGuidance": [
      "Gold is a conductor with many free electrons that allow current to flow easily, whereas Rubber is an insulator with tightly bound electrons that prevent the flow of electricity to the user."
    ],
    "hint": "Focus your answer on the movement (or lack of movement) of electrons in the valence shell of each material."
  }
}

